"""
broadcast.py — Multi-Agent Frequency Broadcast Layer

Allows multiple PrismResonance agents to share a common view of which
operational frequencies are currently active across the system.

When one agent shifts to EMERGENCY frequency, other agents can see that
context shift and adapt their retrieval accordingly — without coupling
their registries together.

Two backends are provided:
  InProcessBroadcast  — dict in shared memory, suitable for threads in
                        the same process (tests, single-node deployments)
  RedisBroadcast      — Redis hash, suitable for distributed multi-agent
                        deployments (requires redis package)

Usage
-----
::

    from prismresonance.broadcast import InProcessBroadcast

    bus = InProcessBroadcast()

    # Agent A shifts to EMERGENCY
    bus.set_frequency("agent-a", FrequencyFamily.EMERGENCY)

    # Agent B can read all active frequencies
    freqs = bus.get_frequencies()
    # → {"agent-a": 1.5707...}

    # Broadcast to all: override everyone's active frequency
    bus.broadcast(FrequencyFamily.EMERGENCY)
"""

from __future__ import annotations

import threading
from typing import Dict, Optional

from .frequency import FrequencyFamily


# ─────────────────────────────────────────────────────────────────────────────
# Protocol / base class
# ─────────────────────────────────────────────────────────────────────────────

class FrequencyBroadcast:
    """Abstract base for frequency broadcast backends."""

    def register_agent(self, agent_id: str, initial_frequency: FrequencyFamily | float = FrequencyFamily.NEUTRAL) -> None:
        raise NotImplementedError

    def unregister_agent(self, agent_id: str) -> None:
        raise NotImplementedError

    def set_frequency(self, agent_id: str, frequency: FrequencyFamily | float) -> None:
        raise NotImplementedError

    def get_frequency(self, agent_id: str) -> Optional[float]:
        raise NotImplementedError

    def get_frequencies(self) -> Dict[str, float]:
        raise NotImplementedError

    def broadcast(self, frequency: FrequencyFamily | float) -> None:
        """Override all registered agents with a single frequency."""
        raise NotImplementedError

    def dominant_frequency(self) -> float:
        """
        Return the most common active frequency across agents.
        Useful as a consensus signal for a new agent joining mid-session.
        """
        freqs = self.get_frequencies()
        if not freqs:
            return FrequencyFamily.NEUTRAL.value
        # Bin into nearest FrequencyFamily and pick the most common
        bins: Dict[str, float] = {}
        for phi in freqs.values():
            name = FrequencyFamily.nearest(phi).name
            bins[name] = bins.get(name, 0) + 1
        dominant_name = max(bins, key=lambda k: bins[k])
        return FrequencyFamily[dominant_name].value


# ─────────────────────────────────────────────────────────────────────────────
# In-process backend (threads in same process)
# ─────────────────────────────────────────────────────────────────────────────

class InProcessBroadcast(FrequencyBroadcast):
    """
    Thread-safe in-process broadcast bus.

    All agents in the same Python process share one dict behind an RLock.
    Zero external dependencies — suitable for tests and single-node setups.
    """

    def __init__(self) -> None:
        self._state: Dict[str, float] = {}
        self._lock  = threading.RLock()

    def register_agent(self, agent_id: str, initial_frequency: FrequencyFamily | float = FrequencyFamily.NEUTRAL) -> None:
        with self._lock:
            self._state[agent_id] = float(initial_frequency)

    def unregister_agent(self, agent_id: str) -> None:
        with self._lock:
            self._state.pop(agent_id, None)

    def set_frequency(self, agent_id: str, frequency: FrequencyFamily | float) -> None:
        with self._lock:
            self._state[agent_id] = float(frequency)

    def get_frequency(self, agent_id: str) -> Optional[float]:
        with self._lock:
            return self._state.get(agent_id)

    def get_frequencies(self) -> Dict[str, float]:
        with self._lock:
            return dict(self._state)

    def broadcast(self, frequency: FrequencyFamily | float) -> None:
        phi = float(frequency)
        with self._lock:
            for agent_id in self._state:
                self._state[agent_id] = phi


# ─────────────────────────────────────────────────────────────────────────────
# Redis backend (distributed multi-agent)
# ─────────────────────────────────────────────────────────────────────────────

class RedisBroadcast(FrequencyBroadcast):
    """
    Redis-backed broadcast bus for distributed multi-agent deployments.

    Requires: pip install redis

    All frequency state is stored in a Redis hash at `redis_key`.
    Multiple processes / machines can read and write via the same key.

    Parameters
    ----------
    redis_url : Redis connection URL (e.g. "redis://localhost:6379/0")
    redis_key : Hash key under which agent frequencies are stored.
    ttl       : Optional TTL in seconds for the hash (None = no expiry).
    """

    def __init__(
        self,
        redis_url: str = "redis://localhost:6379/0",
        redis_key: str = "prismresonance:frequencies",
        ttl: Optional[int] = None,
    ) -> None:
        try:
            import redis
        except ImportError as exc:
            raise ImportError(
                "RedisBroadcast requires the redis package: pip install redis"
            ) from exc

        import redis as _redis
        self._client  = _redis.from_url(redis_url, decode_responses=True)
        self._key     = redis_key
        self._ttl     = ttl

    def register_agent(self, agent_id: str, initial_frequency: FrequencyFamily | float = FrequencyFamily.NEUTRAL) -> None:
        self._client.hset(self._key, agent_id, str(float(initial_frequency)))
        if self._ttl:
            self._client.expire(self._key, self._ttl)

    def unregister_agent(self, agent_id: str) -> None:
        self._client.hdel(self._key, agent_id)

    def set_frequency(self, agent_id: str, frequency: FrequencyFamily | float) -> None:
        self._client.hset(self._key, agent_id, str(float(frequency)))

    def get_frequency(self, agent_id: str) -> Optional[float]:
        val = self._client.hget(self._key, agent_id)
        return float(val) if val is not None else None

    def get_frequencies(self) -> Dict[str, float]:
        raw = self._client.hgetall(self._key)
        return {k: float(v) for k, v in raw.items()}

    def broadcast(self, frequency: FrequencyFamily | float) -> None:
        phi = str(float(frequency))
        existing = self._client.hkeys(self._key)
        if existing:
            mapping = {agent_id: phi for agent_id in existing}
            self._client.hset(self._key, mapping=mapping)
